        aggregation_funcs = {}

    aggregated = defaultdict(lambda: {
        'count': 0,
        'sum_score': 0.0,
        'max_score': float('-inf'),
        'min_score': float('inf'),
        **{field: [] for field in aggregation_funcs.keys()}
    })

