            group_value = 'unknown'

        # Update default statistics
        aggregated[group_value]['count'] += 1
        aggregated[group_value]['sum_score'] += result.score
        if result.score > aggregated[group_value]['max_score']:
            aggregated[group_value]['max_score'] = result.score
        if result.score < aggregated[group_value]['min_score']:
            aggregated[group_value]['min_score'] = result.score

        # Collect data for custom aggregations
        for field_name, _ in aggregation_funcs.items():
            # Try to get field value from metadata or top-level fields
            if field_name == 'score':
                value = result.score
            elif field_name == 'id':
                value = result.id
            elif field_name == 'text':
                value = result.text
            else:
                value = metadata.get(field_name)

            aggregated[group_value][field_name].append(value)

    # Compute final results
    final_results = {}
    for group_value, stats in aggregated.items():
        group_stats = {
            'count': stats['count'],
            'avg_score': stats['sum_score'] / stats['count'] if stats['count'] > 0 else 0.0,
            'max_score': stats['max_score'],
            'min_score': stats['min_score']
        }

